import { useEffect, useState } from 'react';

import {
  Container,
  Grid,
  Typography,
  CircularProgress,
  ThemeProvider,
  Alert,
  Chip,
  Box,
  Radio,
  FormControlLabel,
  RadioGroup,
  Divider,
  IconButton,
  Tooltip,
  Modal,
} from '@mui/material';

import { toast } from '../../utils/toast';
import theme, { materialTheme } from '../../theme';
import styled from '@emotion/styled';
import { SearchType } from './types';
import ConfigBlock from './ConfigBlock';
import Collapsible from '../../components/Collapsible';
import Card from '../../components/Card';
import Button, { ButtonVariant, ButtonSize } from '../../components/Button';
import useSemanticSearchConfig from '../../hooks/useSemanticSearchConfig';
import StyledSwitch from '../../components/Switch/StyledSwitch';
import Form from '../../components/Form';
import { ReactComponent as SparkleIcon } from './sparkle-icon.svg';
import { ReactComponent as DocumentIcon } from './document-icon.svg';
import InfoOutlinedIcon from '@mui/icons-material/InfoOutlined';
import { isMultisite } from '../../utils/isMultisite';
import {
  AddSemanticFieldsCard,
  HybridSettingsCard,
  SemanticSettingsCard,
} from './Common';
import useFetchSearchConfig from '../../hooks/useFetchSearchConfig';

const fuzzinessTooltipText = `WP Engine Smart Search will attempt to search for a match to every word in a
search query exactly until Fuzziness is enabled.

Once fuzziness is enabled it employs a one-letter-per-word tolerance ("distance") by
default, so if you type "Hallo Warld" by accident you will get the
results for both "Hello" and "World". You can increase this per-word
distance to a maximum of 2, so "Haalo Waald" would work as per the
previous example.

Please note that the higher the fuzziness distance
allowed the greater the performance & relevancy hit will be to your
search experience.`;

const stemmingTooltipText = `Stemming is the process of reducing a word to its root form.
This ensures variants of a word match during a search.
For example, walking and walked can be stemmed to the same root word: walk.
Once stemmed, an occurrence of either word would match the other in a search.`;

const SearchConfigurationContainer = styled.div``;

const RadioGroupContainer = styled.div`
  display: flex;
  justify-content: space-between;
  gap: 24px;
  flex-wrap: wrap;
`;

interface SearchConfigurationProps {
  searchType: SearchType;
  onChange?: (value: SearchType) => void;
}
export const SearchConfiguration = ({
  searchType,
  onChange,
}: SearchConfigurationProps) => {
  const handleChange = (value: string) => {
    if (onChange) {
      onChange(value as SearchType);
    }
  };

  return (
    <SearchConfigurationContainer data-testid="search-configuration-radios-container">
      <RadioGroupContainer>
        <Form.LabeledRadioField
          value="fullText"
          label={
            <div>
              Full text{' '}
              <Typography component="i" fontSize="14px">
                Default
              </Typography>
            </div>
          }
          isChecked={searchType === 'fullText'}
          onChange={handleChange}
        >
          Keyword search against your regular search index.
        </Form.LabeledRadioField>
        <Form.LabeledRadioField
          value="hybrid"
          label={
            <div>
              Hybrid{'  '}
              <Chip
                data-testid="hybrid-radio"
                sx={{
                  border: '1px solid #CFDDE9',
                  padding: '6px, 12px, 6px, 12px',
                  backgroundColor: '#F4F7FA',
                  color: '#3e8bff',
                  height: 'auto',
                }}
                label={
                  <Box display="flex" alignItems="center">
                    AI Powered <SparkleIcon />
                  </Box>
                }
              />
            </div>
          }
          isChecked={searchType === 'hybrid'}
          onChange={handleChange}
        >
          AI Powered Incorporates a combination of keyword and semantic search.
        </Form.LabeledRadioField>
        <Form.LabeledRadioField
          value="semantic"
          label={
            <div>
              Semantic{'  '}
              <Chip
                data-testid="semantic-radio"
                sx={{
                  border: '1px solid #CFDDE9',
                  padding: '6px, 12px, 6px, 12px',
                  backgroundColor: '#F4F7FA',
                  color: '#3e8bff',
                  height: 'auto',
                }}
                label={
                  <Box display="flex" alignItems="center">
                    AI Powered <SparkleIcon />
                  </Box>
                }
              />
            </div>
          }
          isChecked={searchType === 'semantic'}
          onChange={handleChange}
        >
          Incorporates semantics using a vectorized database.
        </Form.LabeledRadioField>
      </RadioGroupContainer>
    </SearchConfigurationContainer>
  );
};

function Capitalize(string: string) {
  return string.charAt(0).toUpperCase() + string.slice(1);
}

export default function SearchConfigPage() {
  const {
    fields,
    setFields,
    saveSemanticSearchConfig,
    searchBias,
    setSearchBias,
    enabled,
    setEnabled,
  } = useSemanticSearchConfig();
  const [open, setOpen] = useState(false);
  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);
  const [textFieldValue, setTextFieldValue] = useState('');
  const { loading, error, config, setConfig, saveSearchConfig } =
    useFetchSearchConfig();

  useEffect(() => {
    setEnabled(
      config?.searchType === 'semantic' || config?.searchType === 'hybrid'
    );
  }, [enabled, config?.searchType, setEnabled]);

  const chooseField = (field: string) => {
    setFields([field]);
  };

  const removeField = () => {
    setFields([]);
  };

  const setSearchType = (searchType: SearchType) => {
    setConfig((previousConfig) => {
      if (!previousConfig) return null;

      return {
        ...previousConfig,
        searchType,
      };
    });
  };

  if (config !== null && config.disabledModelNames === undefined) {
    config.disabledModelNames = [];
  }
  if (config !== null && config.searchType === undefined) {
    config.searchType = 'fullText';
  }
  const [fuzzyEnabled, setFuzzyEnabled] = useState(false);

  const handleFuzzyEnabled = () => {
    setFuzzyEnabled(true);
    if (config) {
      setConfig({
        ...config,
        fuzzy: {
          ...config.fuzzy,
          enabled: true,
        },
      });
    }
  };
  const handleFuzzyDisabled = () => {
    setFuzzyEnabled(false);
    if (config) {
      setConfig({
        ...config,
        fuzzy: {
          ...config.fuzzy,
          enabled: false,
        },
      });
    }
  };

  const handleToggle = (modelName: string) => {
    return (_event: React.ChangeEvent<HTMLInputElement>, newValue: boolean) => {
      setConfig((previousConfig) => {
        if (!previousConfig) return null; // handle null case

        let updatedToggleModelNames;
        let previousToggleModelName = previousConfig.disabledModelNames || [];

        if (newValue) {
          updatedToggleModelNames = previousToggleModelName.filter(
            (name) => name !== modelName
          );
        } else {
          updatedToggleModelNames = [...previousToggleModelName, modelName];
        }

        let newConfig = {
          ...previousConfig,
          disabledModelNames: updatedToggleModelNames,
        };

        return newConfig;
      });
    };
  };

  const handleTextFieldChange = (
    event: React.ChangeEvent<HTMLInputElement>
  ) => {
    setTextFieldValue(event.target.value);
  };

  const saveConfig = async () => {
    let result;
    if (isMultisite()) {
      result = await saveSearchConfig(config);
    } else {
      await saveSearchConfig(config);
      result = await saveSemanticSearchConfig();
    }
    if (result) {
      const additionalMessage = enabled
        ? 'Please re-index for any field changes that have been made.'
        : '';
      const successMessage = `Search Config saved! ${additionalMessage}`;
      toast(successMessage, 'success');
    }
  };

  if (loading) {
    return <CircularProgress />;
  }

  if (error) {
    return (
      <ThemeProvider theme={materialTheme}>
        <Container
          data-testid="search-config-container"
          maxWidth="xl"
          disableGutters
        >
          <Grid container spacing={2} mb={2}>
            <Grid item xs={8}>
              <Typography variant="h4" sx={{ fontWeight: 'bold' }}>
                Search Config
              </Typography>
            </Grid>
          </Grid>
          <Alert severity="error" data-testid="search-config-alert">
            {error}
          </Alert>
        </Container>
      </ThemeProvider>
    );
  }

  if (!config) {
    return <div>no config</div>;
  }

  const hideOnFullText = config.searchType === 'fullText' ? 'none' : 'grid';
  const hideOnSemantic = config.searchType === 'semantic' ? 'none' : 'grid';
  const showOnHybrid = config.searchType === 'hybrid' ? 'grid' : 'none';
  const disableOnMultisiteSiteAdmin = isMultisite() ? true : false;

  return (
    <ThemeProvider theme={materialTheme}>
      <Modal
        open={open}
        onClose={handleClose}
        aria-labelledby="modal-modal-title"
        aria-describedby="modal-modal-description"
      >
        <Box>
          <AddSemanticFieldsCard
            config={config}
            fields={fields}
            chooseField={chooseField}
            textValue={textFieldValue}
            handleTextValueChange={handleTextFieldChange}
            handleClose={handleClose}
          />
        </Box>
      </Modal>
      <Container
        data-testid="search-config-container"
        maxWidth="xl"
        disableGutters
      >
        <Card
          title="Search configuration"
          action={
            <ThemeProvider theme={theme}>
              <Button
                size={ButtonSize.Medium}
                variant={ButtonVariant.Primary}
                onClick={saveConfig}
                data-testid="save-button"
              >
                Save Configuration
              </Button>
            </ThemeProvider>
          }
        >
          <SearchConfiguration
            searchType={config.searchType}
            onChange={(v) => setSearchType(v)}
          />
        </Card>
        <br style={{ display: showOnHybrid }} />
        <HybridSettingsCard
          sx={{ display: showOnHybrid }}
          searchBias={searchBias}
          setSearchBias={setSearchBias}
          disabled={disableOnMultisiteSiteAdmin}
        />
        <br style={{ display: hideOnFullText }} />
        <SemanticSettingsCard
          sx={{ display: hideOnFullText }}
          fields={fields}
          removeField={removeField}
          handleOpen={handleOpen}
          disabled={disableOnMultisiteSiteAdmin}
        />
        <br style={{ display: hideOnSemantic }} />
        <Card
          title="Full text settings"
          action={null}
          sx={{ display: hideOnSemantic }}
        >
          <Container
            maxWidth="xl"
            disableGutters={true}
            sx={{ border: '1px solid #EAECF0', borderRadius: '4px' }}
          >
            <Grid item xs={2}>
              <FormControlLabel
                sx={{ paddingLeft: '22px' }}
                value="Stemming"
                control={
                  <Radio
                    sx={{
                      width: '16px',
                      height: '16px',
                      background: '#EBF5FA',
                      border: '1px solid #399CCB',
                      color: '#399CCB',
                    }}
                    onClick={handleFuzzyDisabled}
                    checked={!config.fuzzy.enabled}
                  ></Radio>
                }
                label={
                  <Typography
                    variant="h6"
                    sx={{
                      paddingLeft: '22px',
                      paddingTop: '4px',
                      fontSize: '16px',
                      color: '#475467',
                    }}
                  >
                    Stemming{' '}
                    <Tooltip title={stemmingTooltipText}>
                      <IconButton>
                        <InfoOutlinedIcon
                          sx={{
                            marginLeft: '-5px',
                            height: '22px',
                            width: '22px',
                            color: '#475467',
                          }}
                        />
                      </IconButton>
                    </Tooltip>
                  </Typography>
                }
                checked={!config.fuzzy.enabled}
              />
              <Typography
                sx={{
                  fontSize: '15px',
                  color: '#667085',
                  marginLeft: '54px',
                  marginBottom: '24px',
                  paddingRight: '24px',
                }}
              >
                With Stemming on, results will return for a word and its root
                forms. For example: "walking" will return results for "walk,"
                and "walked."
              </Typography>
              <Divider
                variant="fullWidth"
                sx={{ width: '100%', color: '#EAECF0' }}
              />
              <FormControlLabel
                sx={{ paddingLeft: '22px' }}
                value="Fuzziness"
                control={
                  <Radio
                    data-testid="fuzzy-switch"
                    sx={{
                      width: '16px',
                      height: '16px',
                      background: '#EBF5FA',
                      border: '1px solid #399CCB',
                      color: '#399CCB',
                    }}
                    onClick={handleFuzzyEnabled}
                    checked={config.fuzzy.enabled}
                  />
                }
                label={
                  <Typography
                    variant="h6"
                    sx={{
                      paddingLeft: '22px',
                      paddingTop: '4px',
                      fontSize: '16px',
                      color: '#475467',
                    }}
                  >
                    Fuzziness{' '}
                    <Tooltip title={fuzzinessTooltipText}>
                      <IconButton>
                        <InfoOutlinedIcon
                          sx={{
                            marginLeft: '-5px',
                            height: '22px',
                            width: '22px',
                            color: '#475467',
                          }}
                        />
                      </IconButton>
                    </Tooltip>
                  </Typography>
                }
                checked={fuzzyEnabled && config.fuzzy.enabled}
              />
              <Typography
                sx={{
                  fontSize: '15px',
                  color: '#667085',
                  marginLeft: '54px',
                  paddingRight: '24px',
                }}
              >
                Fuzziness will return results for misspelled words. Fuzzy
                distance defines the amount of letters that may be misspelled,
                and still return results.
              </Typography>
              <RadioGroup
                sx={{
                  padding: '16px',
                  marginLeft: '50px',
                }}
                aria-labelledby="fuzzy-value-radio-group"
                value={config.fuzzy.distance.toString()}
              >
                <FormControlLabel
                  value="1"
                  onChange={() =>
                    setConfig({
                      ...config,
                      fuzzy: {
                        ...config.fuzzy,
                        distance: 1,
                      },
                    })
                  }
                  control={
                    <Radio
                      sx={{
                        width: '16px',
                        height: '16px',
                        background: '#EBF5FA',
                        border: '1px solid #399CCB',
                        color: '#399CCB',
                        '&.Mui-disabled .PrivateSwitchBase-input': {
                          opacity: 0,
                        },
                      }}
                      disabled={!config.fuzzy.enabled}
                    />
                  }
                  label={
                    <Typography
                      sx={{
                        paddingLeft: '5px',
                        fontSize: '13px',
                        color: '#344054',
                      }}
                    >
                      1
                    </Typography>
                  }
                />
                <FormControlLabel
                  value="2"
                  onChange={() =>
                    setConfig({
                      ...config,
                      fuzzy: {
                        ...config.fuzzy,
                        distance: 2,
                      },
                    })
                  }
                  sx={{
                    marginTop: '8px',
                  }}
                  control={
                    <Radio
                      data-testid="fuzzy-distance-2-radio"
                      sx={{
                        width: '16px',
                        height: '16px',
                        background: '#EBF5FA',
                        border: '1px solid #399CCB',
                        color: '#399CCB',
                        '&.Mui-disabled .PrivateSwitchBase-input': {
                          opacity: 0,
                        },
                      }}
                      disabled={!config.fuzzy.enabled}
                    />
                  }
                  label={
                    <Typography
                      sx={{
                        paddingLeft: '5px',
                        fontSize: '13px',
                        color: '#344054',
                      }}
                    >
                      2
                    </Typography>
                  }
                />
              </RadioGroup>
            </Grid>
          </Container>
          <Divider
            variant="fullWidth"
            sx={{ width: '100%', color: '#EAECF0' }}
          />
          <Card title="Models" action={null}>
            <Container disableGutters={true} maxWidth={false}>
              <section data-testid="search-config-form">
                {Object.keys(config.models).map((modelName) => (
                  <Collapsible
                    data-testid="post-type"
                    key={`search-config-collapsible-${modelName}`}
                    title={
                      <>
                        <div>
                          <StyledSwitch
                            checked={
                              !config.disabledModelNames.includes(modelName)
                            }
                            inputProps={{ role: `${modelName}-switch` }}
                            onChange={handleToggle(modelName)}
                          />
                        </div>
                        <div
                          style={{ alignContent: 'center', paddingTop: '4px' }}
                        >
                          <DocumentIcon />
                        </div>
                        <div
                          style={{
                            alignContent: 'center',
                            paddingLeft: '8px',
                          }}
                        >
                          <b>{Capitalize(modelName)}</b>
                        </div>
                      </>
                    }
                    expanded={
                      config.disabledModelNames.includes(modelName)
                        ? false
                        : true
                    }
                  >
                    <ConfigBlock
                      key={`config-block-${modelName}`}
                      fields={config.models[modelName]}
                      name=""
                      onChange={(fieldName, updatedConfig) => {
                        const change = {
                          ...config,
                          models: {
                            ...config.models,
                            [modelName]: {
                              ...config.models[modelName],
                              [fieldName]: {
                                ...config.models[modelName][fieldName],
                                ...updatedConfig,
                              },
                            },
                          },
                        };

                        setConfig(change);
                      }}
                    />
                  </Collapsible>
                ))}
              </section>
            </Container>
          </Card>
        </Card>
      </Container>
    </ThemeProvider>
  );
}
